"use client";

import { motion } from "framer-motion";

function NavItem({
  label,
  active,
  dot,
  children,
}: {
  label: string;
  active?: boolean;
  dot?: boolean;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      className={`relative flex flex-1 flex-col items-center gap-1 ${
        active ? "text-white" : "text-uberSecondary"
      }`}
    >
      {/* Ponto azul indicador (item ativo / destaque) */}
      {dot && (
        <span className="absolute -top-1 h-1.5 w-1.5 rounded-full bg-uberBlue" />
      )}
      {children}
      <span className="text-[10px] leading-none">{label}</span>
    </button>
  );
}

